import type { SyntaxNodeRef } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type {
  FilterFieldLezerNodeType,
  FilterFieldStringNode,
  FilterFieldNodeBase,
} from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import {
  removeEscapeCharacters,
  isValidEscapeSequence,
} from '../../escape-characters.js';

/**
 * Convert a string or identifier node.
 * Also returns starts- or ends-with operators if present, since they may not be valid depending on the context.
 * @internal
 */
export function convertIdentifier(
  node: SyntaxNodeRef,
  doc: string,
  context?: FilterFieldLezerNodeType,
): ConvertedLezerNode<
  FilterFieldStringNode,
  {
    isValid: boolean;
    positionOperators: {
      endsWithOperator?: FilterFieldNodeBase['range'];
      startsWithOperator?: FilterFieldNodeBase['range'];
    };
  }
> {
  const { from, to } = node;
  const text = getTextFromRange(node, doc);
  const value = removeEscapeCharacters(
    context === 'String' ? text.slice(1, -1) : text,
  );

  const convertedNode: FilterFieldStringNode = {
    type: 'String',
    range: {
      from,
      to,
    },
    textValue: text,
    value,
  };

  let endsWithOperator;
  let startsWithOperator;

  // Position operators inside strings are currently not detected by the grammar, but
  // by simply checking the first / last character of the string value.
  // The range includes the doublequotes, which need to be excluded for potential errors.
  if (node.name === 'String') {
    endsWithOperator =
      text.slice(1, 2) === '*' ? { from: from + 1, to: from + 2 } : undefined;

    const withoutQuotes = text.slice(1, text.length - 1);
    // check if there is a * at the end that is not escaped
    startsWithOperator = withoutQuotes.match(/(?<!\\)(?:\\\\)*[*]$/)
      ? { from: to - 2, to: to - 1 }
      : undefined;

    convertedNode.value = value.substring(
      endsWithOperator ? 1 : 0,
      value.length - (startsWithOperator ? 1 : 0),
    );
  }

  return {
    convertedNode,
    errors: [],
    isValid: isValidEscapeSequence(text),
    positionOperators: {
      endsWithOperator,
      startsWithOperator,
    },
  };
}
